// playSound puzzle
function playSound(mediaElem, loop) {
    const mediaElems = (Array.isArray(mediaElem) ? mediaElem : [mediaElem]).filter(elem => elem);
    mediaElems.forEach(mediaElem => {
        mediaElem.setLoop(loop);
        mediaElem.play();
    });
}

// Describe this function...
function SoundLogic() {
  if (isAnimationPlaying(getAnimations(['ALL_OBJECTS']))) {
    playSound(List_Sounds[CurrentSoundIndex], false);
  }
}

// stopSound puzzle
function stopSound(mediaElem) {
    const mediaElems = (Array.isArray(mediaElem) ? mediaElem : [mediaElem]).filter(elem => elem);
    mediaElems.forEach(mediaElem => {
        mediaElem.stop();
    });
}

// Describe this function...
function ALL_Sound_Disable() {
  for (var ItemListSounds_index in List_Sounds) {
    let ItemListSounds = List_Sounds[ItemListSounds_index];
    stopSound(ItemListSounds);
  }
}


